const result = $input.first().json;

if (!result || result.valid !== true) {
  throw new Error('Invalid request signature');
}

return [{ json: { hmac_valid: true } }];

const session = $input.first().json;

if (!session || !session.user_id) {
  throw new Error('Invalid or expired token');
}

const body = $('Receive Message Request').first().json.body;

if (!body.session_id) {
  throw new Error('session_id is required');
}

const canViewAll = ['owner', 'admin'].includes(session.role);
const target_user_id = (canViewAll && body.target_user_id)
  ? body.target_user_id
  : session.user_id;

return [{
  json: {
    user_id: session.user_id,
    target_user_id,
    role: session.role,
    client_id: session.client_id,
    slug: session.slug,
    session_id: body.session_id
  }
}];

const points = $input.first().json.result.points;

if (!points || points.length === 0) {
  return [{ json: { messages: [], session_id: $('Check Token Valid').first().json.session_id } }];
}

const messages = points
  .map(p => ({ question: p.payload.question, answer: p.payload.answer, sources: p.payload.sources, timestamp: p.payload.timestamp, message_index: p.payload.message_index }))
  .sort((a, b) => a.message_index - b.message_index);

return [{ json: { session_id: $('Check Token Valid').first().json.session_id, messages } }];
